def is_valid_hex(s):
    if len(s) != 7:
        return False
    if not s.startswith('#'):
        return False
    hex_digits = s[1:]
    allowed = "0123456789abcdefABCDEF"
    for char in hex_digits:
        if char not in allowed:
            return False
    return True

strings = ['#1a2b3c', '#FFF', '123456', '#abcdez', '#000000', '#AABBCC', '#12 34 56']
valid = [s for s in strings if is_valid_hex(s)]
print(f"Valid strings: {valid}")
print(f"Count: {len(valid)}")

def get_even_fibs_under_limit(limit):
    fibs = [0, 1]
    while True:
        next_fib = fibs[-1] + fibs[-2]
        if next_fib >= limit:
            break
        fibs.append(next_fib)

    even_fibs = [f for f in fibs if f % 2 == 0]
    return even_fibs, sum(even_fibs)

even_fibs, total_sum = get_even_fibs_under_limit(100)
print(f"Even Fibonacci numbers under 100: {even_fibs}")
print(f"Sum: {total_sum}")
